const bin = $input.first().binary?.data;
if (!bin) return [{ json: { overdue: [], count: 0, today: new Date().toISOString().split('T')[0], areas_with_overdue: [] } }];
const content = Buffer.from(bin.data, 'base64').toString('utf-8');
const today = new Date().toISOString().split('T')[0];

const overdue = [];
const re = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
let m;
while ((m = re.exec(content)) !== null) {
  const [, desc, area, priority, due] = m;
  if (!due) continue;
  if (due < today) {
    const daysOverdue = Math.floor((new Date(today) - new Date(due)) / 86400000);
    overdue.push({ task: desc.trim(), area, priority, due, daysOverdue,
      urgency: daysOverdue >= 8 ? 'critical' : daysOverdue >= 4 ? 'high' : 'medium' });
  }
}

// Sort by days overdue descending (most overdue first)
overdue.sort((a, b) => b.daysOverdue - a.daysOverdue);

const areas_with_overdue = [...new Set(overdue.map(t => t.area))];
return [{ json: { overdue, count: overdue.length, today, areas_with_overdue } }];

const { overdue, count, today } = $input.first().json;

if (count === 0) {
  const html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:20px">
    <div style="background:#16a34a;color:white;padding:20px;border-radius:8px;text-align:center">
      <h1 style="margin:0;font-size:22px">&#10003; No Overdue Tasks</h1>
      <p style="margin:5px 0 0;opacity:0.8">${today} — All caught up!</p>
    </div>
  </div>`;
  return [{ json: { html, subject: `Overdue Alert: 0 overdue tasks — ${today}`, count, today } }];
}

function urgencyBadge(days, urgency) {
  if (urgency === 'critical') return `<span style="background:#dc2626;color:white;padding:2px 6px;border-radius:3px;font-size:11px;font-weight:bold">${days} days overdue</span>`;
  if (urgency === 'high')     return `<span style="background:#ea580c;color:white;padding:2px 6px;border-radius:3px;font-size:11px">${days} days overdue</span>`;
  return                              `<span style="background:#d97706;color:white;padding:2px 6px;border-radius:3px;font-size:11px">${days} days overdue</span>`;
}

function priorityBadge(p) {
  const colors = { A: '#7c3aed', B: '#0284c7', C: '#6b7280' };
  return `<span style="background:${colors[p]||'#6b7280'};color:white;padding:1px 5px;border-radius:2px;font-size:10px;font-weight:bold">${p}</span>`;
}

const byArea = {};
for (const t of overdue) {
  if (!byArea[t.area]) byArea[t.area] = [];
  byArea[t.area].push(t);
}

let taskRows = '';
for (const [area, tasks] of Object.entries(byArea)) {
  taskRows += `<tr><td colspan="3" style="padding:10px 12px 4px;font-weight:bold;text-transform:capitalize;font-size:14px;color:#1a1a2e;border-top:2px solid #e5e7eb">${area}</td></tr>`;
  for (const t of tasks) {
    const rowBg = t.urgency === 'critical' ? '#fff1f2' : t.urgency === 'high' ? '#fff7ed' : '#fffbeb';
    taskRows += `<tr style="background:${rowBg}">
      <td style="padding:8px 12px;width:30px">${priorityBadge(t.priority)}</td>
      <td style="padding:8px 12px;font-size:13px">${t.task}<br><span style="font-size:11px;color:#6b7280">Due: ${t.due}</span></td>
      <td style="padding:8px 12px;text-align:right;white-space:nowrap">${urgencyBadge(t.daysOverdue, t.urgency)}</td>
    </tr>`;
  }
}

const critCount = overdue.filter(t => t.urgency === 'critical').length;
const highCount = overdue.filter(t => t.urgency === 'high').length;
const medCount  = overdue.filter(t => t.urgency === 'medium').length;
const headerColor = critCount > 0 ? '#dc2626' : highCount > 0 ? '#ea580c' : '#d97706';

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:20px">
  <div style="background:#1a1a2e;color:white;padding:20px;border-radius:8px 8px 0 0">
    <h1 style="margin:0;font-size:22px">&#9888;&#65039; Overdue Task Alert</h1>
    <p style="margin:5px 0 0;opacity:0.8">${today}</p>
  </div>
  <div style="background:${headerColor};color:white;padding:12px 20px;margin:2px 0;text-align:center">
    <span style="font-size:28px;font-weight:bold">${count}</span>
    <span style="margin-left:10px;font-size:16px">tasks overdue</span>
    <div style="margin-top:6px;font-size:12px;opacity:0.9">
      ${critCount > 0 ? `<span style="background:rgba(0,0,0,0.2);padding:2px 8px;border-radius:3px;margin:2px">${critCount} critical (8+ days)</span>` : ''}
      ${highCount > 0 ? `<span style="background:rgba(0,0,0,0.2);padding:2px 8px;border-radius:3px;margin:2px">${highCount} high (4-7 days)</span>` : ''}
      ${medCount  > 0 ? `<span style="background:rgba(0,0,0,0.2);padding:2px 8px;border-radius:3px;margin:2px">${medCount} medium (1-3 days)</span>` : ''}
    </div>
  </div>
  <div style="background:white;padding:4px 0;margin:2px 0">
    <table style="width:100%;border-collapse:collapse"><tbody>${taskRows}</tbody></table>
  </div>
  <div style="background:#374151;color:white;padding:12px 20px;border-radius:0 0 8px 8px;text-align:center;font-size:11px">
    Life OS Overdue Alert &middot; ${today} &middot; ObsidianHomeOrchestrator
  </div>
</div>`.trim();

return [{ json: { html, subject: `Overdue Alert: ${count} tasks (${critCount} critical) — ${today}`, count, today } }];

const { count, today, areas_with_overdue } = $input.first().json;
const log = JSON.stringify({
  workflow: 'overdue-task-alert-v2',
  run_date: today,
  status: 'success',
  overdue_count: count,
  areas_with_overdue: areas_with_overdue || [],
  generated_at: new Date().toISOString()
}, null, 2);
return [{ json: { logKey: `99_System/logs/overdue-task-alert-${today}.json`, logContent: log } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, "utf-8");
return [{ json: $json, binary: { data: { data: buf.toString("base64"), mimeType: "application/json", fileName: key.split("/").pop(), fileExtension: "json", fileSize: buf.length } } }];
